import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as a string
        String data = new String(System.in.readAllBytes(), StandardCharsets.UTF_8);
        // Convert escaped newlines ("\\n") to actual whitespace
        data = data.replace("\\n", " ");
        data = data.replace("\\r", " ");
        // Tokenize by any whitespace
        StringTokenizer st = new StringTokenizer(data);
        if (!st.hasMoreTokens()) return;
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            if (!st.hasMoreTokens()) break;
            int n = Integer.parseInt(st.nextToken());
            int[] h = new int[n];
            for (int i = 0; i < n; i++) {
                if (!st.hasMoreTokens()) h[i] = 0; else h[i] = Integer.parseInt(st.nextToken());
            }
            int[] ans = new int[n];
            Arrays.fill(ans, -1);
            ArrayDeque<Integer> stack = new ArrayDeque<>();
            for (int i = 0; i < n; i++) {
                while (!stack.isEmpty() && h[i] > h[stack.peek()]) {
                    ans[stack.pop()] = h[i];
                }
                stack.push(i);
            }
            for (int i = 0; i < n; i++) {
                if (i > 0) out.append(' ');
                out.append(ans[i]);
            }
            if (tc < T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

